const { useState, useRef, useCallback, useEffect, useLayoutEffect, useMemo, createContext, useContext } = React;

// ═══════════════════════════════════════════
// ERROR BOUNDARY — catches render errors in any wrapped subtree and shows
// a friendly fallback instead of crashing the whole app.
// Must be a class component (React requirement for error boundaries).
// Usage: <ErrorBoundary label="CD Dashboard" onReset={()=>navigate("home")}>
//           <CDDashboard .../>
//        </ErrorBoundary>
// ═══════════════════════════════════════════
class ErrorBoundary extends React.Component {
  constructor(props){
    super(props);
    this.state={hasError:false,error:null};
  }
  static getDerivedStateFromError(error){
    return{hasError:true,error};
  }
  componentDidCatch(error,info){
    const label=this.props.label||"section";
    console.error(`[CS ErrorBoundary: ${label}]`,error.message,info.componentStack);
    // Collect into a global list so the ?debug panel can surface it
    try{
      window.__SC_ERR=window.__SC_ERR||[];
      window.__SC_ERR.push({label,msg:error.message,stack:info.componentStack,ts:new Date().toISOString()});
    }catch(_){}
  }
  render(){
    if(this.state.hasError){
      const{label,onReset}=this.props;
      const showDebug=typeof window!=="undefined"&&(window.location.search.includes("debug")||window.location.hash.includes("debug"));
      return(
        <div style={{minHeight:"60vh",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:16,padding:"40px 24px",textAlign:"center"}}>
          <div style={{fontSize:40,lineHeight:1}}>⚠️</div>
          <h2 style={{fontSize:20,fontWeight:800,margin:0}}>
            {label?`${label} ran into a problem`:"Something went wrong"}
          </h2>
          <p style={{color:"var(--t2)",fontSize:14,maxWidth:440,lineHeight:1.65,margin:0}}>
            This section could not be displayed. The rest of the site is still working.<br/>
            Please refresh the page or go back to the dashboard.
          </p>
          <div style={{display:"flex",gap:12,flexWrap:"wrap",justifyContent:"center"}}>
            <button className="btn-p" onClick={()=>window.location.reload()}>↻ Refresh</button>
            {onReset&&<button className="btn-s" onClick={()=>{this.setState({hasError:false,error:null});onReset();}}>← Back to Dashboard</button>}
          </div>
          {showDebug&&this.state.error&&(
            <details style={{marginTop:8,fontSize:11,color:"var(--t3)",maxWidth:600,textAlign:"left"}}>
              <summary style={{cursor:"pointer",fontWeight:600}}>Error details (debug)</summary>
              <pre style={{whiteSpace:"pre-wrap",wordBreak:"break-all",marginTop:8,background:"var(--s2)",padding:12,borderRadius:8}}>
                {String(this.state.error)}
              </pre>
            </details>
          )}
        </div>
      );
    }
    return this.props.children;
  }
}

// ═══════════════════════════════════════════
// LANGUAGE / i18n SYSTEM
// ═══════════════════════════════════════════
const LanguageContext = createContext({ lang: 'en', setLang: ()=>{} });
const useLanguage = () => useContext(LanguageContext);
const useT = () => {
  const { lang } = useContext(LanguageContext);
  return (key) => (TRANSLATIONS[lang] && TRANSLATIONS[lang][key]) || (TRANSLATIONS.en[key]) || key;
};

