// ─── Casting Type Label Translation ──────────────────────────────────────────
function translateCastingType(type, lang) {
  if (lang === 'en' || !type) return type;
  const map = {
    'Film': 'Película', 'TV': 'Serie de TV', 'Commercial': 'Comercial',
    'Theater': 'Teatro', 'Broadway': 'Broadway', 'Short Film': 'Cortometraje',
    'Modeling': 'Modelaje', 'Indie Film': 'Película independiente', 'Web Series': 'Serie web',
  };
  return map[type] || type;
}

// ─── Role Type Translation ────────────────────────────────────────────────────
function translateRoleType(type, lang) {
  if (lang === 'en' || !type) return type;
  const map = {
    'Lead': 'Protagonista', 'Supporting': 'Secundario', 'Featured': 'Destacado',
    'Series Regular': 'Regular de serie', 'Recurring': 'Recurrente',
    'Guest Star': 'Estrella invitada', 'Principal': 'Principal', 'Ensemble': 'Conjunto',
    'Real People': 'Personas reales', 'Parts': 'Partes',
  };
  return map[type] || type;
}

// Selectable role/billing types for casting roles (CD post form + admin generator).
const ROLE_TYPE_OPTIONS=["Lead","Supporting","Principal","Featured","Co-Star","Guest Star","Recurring","Series Regular","Day Player","Background","Featured Background","Stand-In","Photo Double","Body Double","Stunt Performer","Voiceover","Host","Dancer","Singer","Understudy","Swing","Ensemble"];
// Best-guess role type from a role name (used to seed auto-generated castings so
// they don't all default to "Supporting"). Admins can override in the edit form.
function inferRoleTypeFromText(n){
  if(!n)return null;
  if(/photo double/.test(n))return"Photo Double";
  if(/body double/.test(n))return"Body Double";
  if(/stunt/.test(n))return"Stunt Performer";
  if(/stand-in|stand in/.test(n))return"Stand-In";
  if(/featured background/.test(n))return"Featured Background";
  if(/voice|narrat|jingle|animation voice|spokesperson vo/.test(n))return"Voiceover";
  if(/host|presenter/.test(n))return"Host";
  if(/dancer|movement/.test(n))return"Dancer";
  if(/day player/.test(n))return"Day Player";
  if(/featured/.test(n))return"Featured";
  if(/\blead\b|\bleader\b|leading role|protagonist|spokesperson/.test(n))return"Lead";
  if(/supporting|foil|antagonist|straight man/.test(n))return"Supporting";
  if(/ensemble|ensamble|reader|sketch player|house team|workshop participant|reenactor|multiple roles/.test(n))return"Ensemble";
  if(/background|party guest|audience|extra|crew member/.test(n))return"Background";
  if(/guest|panelist|interview subject|storyteller|sidekick/.test(n))return"Guest Star";
  if(/singer|vocalist/.test(n))return"Singer";
  if(/lifestyle|model|figure model/.test(n))return"Principal";
  return null;
}
// Infer a role's type. The name is most authoritative; if it yields nothing,
// fall back to the description — casting copy routinely states the billing
// there ("...25–35. Lead.", "Featured.", "leader of the crew") even when the
// role name is just a character name (RAYA, DANTE). Without this, every
// character-named role collapsed to "Supporting".
function inferRoleType(name,description){
  return inferRoleTypeFromText((name||"").toLowerCase())
    || inferRoleTypeFromText((description||"").toLowerCase())
    || "Supporting";
}

// Rank used to order roles within a casting: lead/big roles first, background last.
const ROLE_TYPE_RANK={Lead:0,"Series Regular":1,Principal:2,Supporting:3,"Co-Star":4,Recurring:5,"Guest Star":6,Featured:7,Host:8,Voiceover:9,Singer:10,Dancer:11,Understudy:12,Swing:13,Ensemble:14,"Day Player":15,"Stand-In":16,"Photo Double":17,"Body Double":18,"Stunt Performer":19,"Featured Background":20,Background:21};
function roleTypeRank(t){const r=ROLE_TYPE_RANK[t||"Supporting"];return r===undefined?12:r;}
// A role field counts as "open to anyone" when it's blank, "any", "all", or already
// phrased as "any …". We turn those into explicit, non-vague labels so a casting that
// was posted open to everyone reads "Any age range" / "Any ethnicity" instead of a bare "Any".
function isAnyRoleVal(v){const s=(""+(v==null?"":v)).trim().toLowerCase();return !s||s==="any"||s==="all"||s.startsWith("any ")||s.startsWith("all ");}
function roleGenderLabel(v){return isAnyRoleVal(v)?"Any gender":v;}
function roleAgeLabel(v){return isAnyRoleVal(v)?"Any age range":("Age "+v);}
function roleEthnicityLabel(v){return isAnyRoleVal(v)?"Any ethnicity":v;}
// Stable comparator (rank, then id) so the display list and the audition-role
// index map (fetched separately) always order identically.
function compareRolesByType(aType,aId,bType,bId){
  return roleTypeRank(aType)-roleTypeRank(bType) || String(aId).localeCompare(String(bId));
}

// Name to show for the OTHER party in a message thread. For admin-generated
// castings, talent should see the casting's Production Company (posted_by_label/
// prod) instead of the platform/admin profile name. Normal CD castings are
// unchanged — their own profile name is used.
function posterDisplayName(profile,casting,fallback){
  const adminPoster = casting && casting.is_admin_created &&
    (profile?.user_type==="admin"||profile?.user_type==="super_admin");
  if(adminPoster){
    // Source / casting director is whatever is in the Production Company (prod)
    // field. Never surface the platform "CastSlate ..." label.
    const name=(casting.prod||casting.posted_by_label||"").trim();
    return name && !/castslate/i.test(name) ? name : "Casting Director";
  }
  return profile?.display_name||profile?.company_name||fallback||"Unknown user";
}

// True when a message counterparty is the casting side of a conversation — a real
// CD/producer/studio, or the platform/office (admin) account, which to talent is
// always a casting entity (admin-generated castings AND plain office DMs). Talent
// must never open a profile for these, and their avatar shows a default
// director's-chair icon instead of a headshot/"?" placeholder. (isAdminCreated is
// no longer needed for the boolean — admin senders always count — but kept for
// call-site compatibility.)
function isCastingSideSender(userType,isAdminCreated){
  const t=(userType||"").toLowerCase();
  return t==="cd"||t==="producer"||t==="studio"||t==="admin"||t==="super_admin";
}

// Default director's-chair avatar used for casting-side senders across the inbox
// list and the thread modal. Inert by design — never opens a profile.
function DirectorChairAvatar({size=52}){
  const icon=Math.round(size*0.5);
  return(<div style={{width:size,height:size,borderRadius:"50%",flexShrink:0,background:"var(--s2)",border:"1px solid var(--bdr)",display:"flex",alignItems:"center",justifyContent:"center",color:"var(--t2)"}} aria-hidden="true">
    <svg viewBox="0 0 24 24" width={icon} height={icon} fill="none" stroke="currentColor" strokeWidth="1.7" strokeLinecap="round" strokeLinejoin="round">
      <line x1="4" y1="3.5" x2="20" y2="3.5"/>
      <line x1="4" y1="6.5" x2="20" y2="6.5"/>
      <line x1="5" y1="3" x2="5" y2="11"/>
      <line x1="19" y1="3" x2="19" y2="11"/>
      <line x1="4" y1="11" x2="20" y2="11"/>
      <line x1="6.5" y1="11" x2="17.5" y2="21"/>
      <line x1="17.5" y1="11" x2="6.5" y2="21"/>
    </svg>
  </div>);
}

// Project / production types offered in the CD post form and the admin generator.
const PROJECT_TYPE_OPTIONS=["Feature Film","Short Film","Student Film","Independent Film","Documentary","TV Series","TV Pilot","Web Series","Streaming Series","Commercial","Social Media Ad","Branded Content","Corporate Video","Industrial / Training Video","Promo Video","Product Demo","Music Video","Voiceover","Podcast / Audio Drama","Animation","Video Game","Theater","Off-Broadway Theater","Off-Off-Broadway Theater","Musical Theater","Workshop / Staged Reading","Live Event","Hosting / Presenter","Reality / Docu-Series","Lifestyle / Unscripted","Modeling","Print Campaign","Photo Shoot","Influencer / UGC Content","Educational Video","Public Service Announcement","Spec Commercial","Proof of Concept","Sizzle Reel","Pitch Trailer","Table Read","Experimental Film","Dance Project","Performance Art","Background / Extras","Stand-In","Body Double","Stunts","Motion Capture","Other"];

// ─── Spanish Casting Translations ────────────────────────────────────────────
// Seeded/demo castings fully translated. User-generated castings from the DB
// would need a server-side translation API (e.g. DeepL, Google Translate) or
