// ─── Get translated casting (for display) ────────────────────────────────────
// Returns a casting with Spanish fields merged in when lang==='es'.
// The original English data is never modified.
function getTranslatedCasting(casting, lang) {
  if (lang === 'en' || !casting) return casting;
  const es = CASTINGS_ES[casting.slug];
  if (!es) return casting;
  return {
    ...casting,
    title: es.title || casting.title,
    tagline: es.tagline || casting.tagline,
    type: es.type || casting.type,
    desc: es.desc || casting.desc,
    synopsis: es.synopsis || casting.synopsis,
    roles: (casting.roles || []).map((r, i) => {
      const esRole = es.roles && es.roles[i];
      if (!esRole) return { ...r, type: translateRoleType(r.type, lang) };
      return { ...r, name: esRole.name || r.name, type: esRole.type || translateRoleType(r.type, lang), desc: esRole.desc || r.desc };
    }),
  };
}

