// PAGE: PRICING
// ═══════════════════════════════════════════
function PricingPage({session,myProfile,onNavigate,onPickPlan}){
  const t=useT();
  const vpw=useViewportWidth();
  const isMobile=vpw<768;
  const [premiumMsg,setPremiumMsg]=React.useState(false);

  const isPremium=myProfile?.membership_status==="active";
  const hasStripeSubscription=!!(myProfile?.stripe_subscription_id);
  const isAdminOverride=isPremium&&!hasStripeSubscription;

  // Free/non-premium logged-in users go to membership plan selection.
  // Premium users stay here so they can see their plan status and upgrade options.
  React.useEffect(()=>{
    if(session?.user&&myProfile&&!isPremium){onNavigate("membership");}
  },[session?.user?.id,myProfile?.user_type,myProfile?.membership_status]); // eslint-disable-line react-hooks/exhaustive-deps
  // Suppress for free logged-in users (avoid flash while effect fires)
  if(session?.user&&myProfile&&!isPremium)return null;
  // Profile still loading for a logged-in user — show a brief spinner
  if(session?.user&&!myProfile)return(<div className="page" style={{minHeight:"60vh",display:"flex",alignItems:"center",justifyContent:"center"}}><CastSlateLoader text="Loading…"/></div>);

  const feat=(f,accent)=>(
    <div key={f} style={{display:"flex",gap:9,alignItems:"flex-start",padding:"7px 0",fontSize:13,color:"var(--t2)",lineHeight:1.4}}>
      <span style={{color:accent,fontWeight:800,flexShrink:0,fontSize:13,marginTop:1}}>✓</span>
      <span>{f}</span>
    </div>
  );
  const featureRow=(label,free,premium)=>(
    <div style={{display:"grid",gridTemplateColumns:isMobile?"2fr 1fr 1fr":"1fr 1fr 1fr",gap:isMobile?4:8,padding:"10px 0",borderBottom:"1px solid var(--bdr)",fontSize:isMobile?12:13,alignItems:"center"}}>
      <span style={{color:"var(--t2)"}}>{label}</span>
      <span style={{textAlign:"center",color:"var(--t1)",fontWeight:600}}>{free}</span>
      <span style={{textAlign:"center",color:"var(--acc)",fontWeight:600}}>{premium}</span>
    </div>
  );

  const card={display:"flex",flexDirection:"column",background:"#fff",border:"1.5px solid #e3ddd5",borderRadius:20,padding:28,boxShadow:"0 2px 14px rgba(0,0,0,0.07)"};
  const btnOutline={width:"100%",height:44,border:"1.5px solid #2a2520",borderRadius:10,background:"transparent",color:"#2a2520",fontSize:13,fontWeight:700,cursor:"pointer",letterSpacing:0.2,fontFamily:"inherit"};
  const btnFilled={width:"100%",height:44,border:"none",borderRadius:10,background:"var(--acc)",color:"#fff",fontSize:13,fontWeight:700,cursor:"pointer",letterSpacing:0.2,fontFamily:"inherit"};

  // Helpers for premium status display
  const renewalDate=myProfile?.current_period_end||myProfile?.membership_end_date;
  const renewalExpired=renewalDate&&new Date(renewalDate)<new Date();
  const planKey=myProfile?.plan_type||"monthly";
  const currentPlanInfo=MEMBERSHIP_PLANS[planKey]||MEMBERSHIP_PLANS.monthly;
  const isMonthlyPlan=planKey==="monthly";

  return(
    <div className="page">

      {/* ── Heading ── */}
      <div style={{textAlign:"center",padding:"60px 20px 40px",maxWidth:640,margin:"0 auto"}}>
        <div className="section-label">{t('pricing.title')}</div>
        <h1 style={{fontSize:38,fontWeight:800,letterSpacing:-1.5,lineHeight:1.15,marginBottom:14,color:"var(--t1)"}}>{t('pricing.subtitle')}</h1>
        <p style={{color:"var(--t3)",fontSize:15,lineHeight:1.65,maxWidth:500,margin:"0 auto"}}>{t('pricing.startFree')}</p>
      </div>

      {/* ── Premium member status banner (only for active subscribers) ── */}
      {isPremium&&<div style={{maxWidth:760,margin:"0 auto 32px",padding:"0 20px"}}>
        <div style={{background:"linear-gradient(135deg,rgba(99,60,180,0.08),rgba(99,60,180,0.03))",border:"1.5px solid rgba(99,60,180,0.22)",borderRadius:16,padding:"22px 26px"}}>
          <div style={{display:"flex",alignItems:"flex-start",justifyContent:"space-between",flexWrap:"wrap",gap:14}}>
            <div>
              <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:10}}>
                <span style={{background:"var(--acc)",color:"#fff",fontSize:10,fontWeight:800,letterSpacing:1.2,padding:"3px 10px",borderRadius:100,whiteSpace:"nowrap"}}>PREMIUM</span>
                <h3 style={{fontSize:17,fontWeight:800,margin:0,color:"var(--t1)"}}>You're already a Premium member.</h3>
              </div>
              <div style={{display:"grid",gridTemplateColumns:isMobile?"1fr":"1fr 1fr",gap:"5px 28px"}}>
                <div style={{fontSize:13,color:"var(--t2)"}}><span style={{fontWeight:600,color:"var(--t1)"}}>Current plan:</span> {currentPlanInfo.label}</div>
                <div style={{fontSize:13,color:"var(--t2)"}}><span style={{fontWeight:600,color:"var(--t1)"}}>Status:</span> <span style={{color:renewalExpired?"var(--red)":"var(--grn)",fontWeight:600}}>{renewalExpired?"Expired":"Active"}</span></div>
                {hasStripeSubscription&&<div style={{fontSize:13,color:"var(--t2)"}}><span style={{fontWeight:600,color:"var(--t1)"}}>Billing:</span> ${currentPlanInfo.monthly.toFixed(2)}/month</div>}
                {isAdminOverride&&<div style={{fontSize:13,color:"var(--t2)"}}><span style={{fontWeight:600,color:"var(--t1)"}}>Billing:</span> <span style={{color:"var(--acc)",fontWeight:600}}>Admin/Test Override</span></div>}
                {renewalDate&&hasStripeSubscription&&<div style={{fontSize:13,color:renewalExpired?"var(--red)":"var(--t2)"}}><span style={{fontWeight:600,color:"var(--t1)"}}>{renewalExpired?"Expired:":"Renewal:"}</span> {new Date(renewalDate).toLocaleDateString(undefined,{month:"long",day:"numeric",year:"numeric"})}</div>}
              </div>
              {isMonthlyPlan&&!renewalExpired&&<p style={{fontSize:12,color:"var(--t3)",marginTop:10,marginBottom:0}}>On Monthly? Upgrade to 6-month or yearly below to lock in a lower rate.</p>}
            </div>
            <div style={{display:"flex",gap:8,flexWrap:"wrap",alignItems:"flex-start",flexShrink:0}}>
              <button className="btn-p btn-sm" onClick={()=>onNavigate("account-settings")}>Manage Membership</button>
              <button className="btn-s btn-sm" onClick={()=>onNavigate("my-profile")}>View Premium Features</button>
            </div>
          </div>
        </div>
      </div>}

      {/* ── Cards ── */}
      <div style={{maxWidth:1020,margin:"0 auto 48px",padding:"0 20px 12px"}}>
        <div className="pricing-cards-grid" style={{display:"grid",gridTemplateColumns:isMobile?"1fr":"repeat(3,1fr)",gap:isMobile?16:20,alignItems:"stretch"}}>

          {/* Actor Free */}
          <div style={card}>
            <div style={{height:28}}/>
            <div style={{marginBottom:18}}>
              <div style={{fontSize:11,fontWeight:800,textTransform:"uppercase",letterSpacing:1.3,color:"var(--t3)",marginBottom:3}}>{t('pricing.actorFree')}</div>
              <div style={{fontSize:12,color:"var(--t3)"}}>{t('pricing.actorsModels')}</div>
            </div>
            <div style={{paddingBottom:20,marginBottom:20,borderBottom:"1px solid #ede8e0"}}>
              <div style={{fontFamily:"'DM Sans',sans-serif",fontWeight:800,fontSize:40,color:"var(--t1)",letterSpacing:-1.5,lineHeight:1}}>$0</div>
              <div style={{fontSize:12,color:"var(--t3)",marginTop:5}}>{t('pricing.noCreditCard')}</div>
            </div>
            <div style={{flex:1}}>
              {[t('pricing.freeLabel')+' account','1 headshot','3 submissions per day','Basic actor profile','Browse all castings'].map(f=>feat(f,"var(--grn)"))}
            </div>
            <button style={{...btnOutline,marginTop:24}} onClick={()=>onNavigate("register-talent")}>{t('pricing.getStartedFree')}</button>
          </div>

          {/* Actor Premium */}
          <div style={{...card,border:"2px solid var(--acc)",boxShadow:"0 8px 36px rgba(0,0,0,0.14)",transform:isMobile?"none":"translateY(-10px)"}}>
            <div style={{height:28,display:"flex",alignItems:"center",justifyContent:"center"}}>
              <span style={{background:"var(--acc)",color:"#fff",fontSize:10,fontWeight:800,letterSpacing:1.5,textTransform:"uppercase",padding:"3px 16px",borderRadius:100,whiteSpace:"nowrap"}}>{t('pricing.recommended')}</span>
            </div>
            <div style={{marginBottom:18,marginTop:10}}>
              <div style={{fontSize:11,fontWeight:800,textTransform:"uppercase",letterSpacing:1.3,color:"var(--acc)",marginBottom:3}}>{t('pricing.actorPremium')}</div>
              <div style={{fontSize:12,color:"var(--t3)"}}>{t('pricing.actorsModels')}</div>
            </div>
            <div style={{paddingBottom:20,marginBottom:20,borderBottom:"1px solid #ede8e0"}}>
              <div style={{fontFamily:"'DM Sans',sans-serif",fontWeight:800,fontSize:40,color:"var(--acc)",letterSpacing:-1.5,lineHeight:1}}>$9.99</div>
              <div style={{fontSize:12,color:"var(--t3)",marginTop:5}}>{t('pricing.perMonthCancel')}</div>
            </div>
            <div style={{flex:1}}>
              {['Unlimited media uploads','Unlimited photos, videos & Cast Me As',t('pricing.unlimitedLabel')+' submissions','Actor Slate Video — 7-sec intro','Actor Business Card with QR code','Manager Mode weekly career check-ins','Personalized profile improvement suggestions'].map(f=>feat(f,"var(--acc)"))}
            </div>
            {isPremium
              ?<button className="btn-teal" style={{width:"100%",height:44,borderRadius:10,marginTop:24}} onClick={()=>onNavigate("membership")}>Manage Plan →</button>
              :<button className="btn-teal" style={{width:"100%",height:44,borderRadius:10,marginTop:24}} onClick={()=>onNavigate("membership")}>{t('pricing.getPremium')}</button>}
          </div>

          {/* Casting Director */}
          <div style={card}>
            <div style={{height:28}}/>
            <div style={{marginBottom:18}}>
              <div style={{fontSize:11,fontWeight:800,textTransform:"uppercase",letterSpacing:1.3,color:"var(--t3)",marginBottom:3}}>{t('pricing.castingDir')}</div>
              <div style={{fontSize:12,color:"var(--t3)"}}>{t('pricing.castingProducers')}</div>
            </div>
            <div style={{paddingBottom:20,marginBottom:20,borderBottom:"1px solid #ede8e0"}}>
              <div style={{fontFamily:"'DM Sans',sans-serif",fontWeight:800,fontSize:40,color:"var(--t1)",letterSpacing:-1.5,lineHeight:1}}>{t('pricing.freeLabel')}</div>
              <div style={{fontSize:12,color:"var(--t3)",marginTop:5}}>{t('pricing.toCreate')}</div>
            </div>
            <div style={{flex:1}}>
              {[t('pricing.freeLabel')+' account creation','Verified creators can post castings','Swipe-based talent review','Advanced talent filters'].map(f=>feat(f,"var(--grn)"))}
              <div style={{fontSize:11,color:"var(--t3)",marginTop:14,lineHeight:1.6}}>{t('pricing.postingFees')}</div>
            </div>
            <button style={{...btnOutline,marginTop:24}} onClick={()=>onNavigate("register-cd")}>{t('pricing.createCD')}</button>
          </div>

        </div>
      </div>

      {/* ── Comparison table ── */}
      <div style={{maxWidth:740,margin:"0 auto 40px",padding:"0 20px"}}>
        <div className="card" style={{padding:"24px 28px"}}>
          <h4 style={{fontSize:14,fontWeight:700,marginBottom:16}}>{t('pricing.comparison')}</h4>
          <div style={{display:"grid",gridTemplateColumns:isMobile?"2fr 1fr 1fr":"1fr 1fr 1fr",gap:isMobile?4:8,padding:"8px 0",borderBottom:"2px solid var(--bdr)",fontSize:11,fontWeight:700,textTransform:"uppercase",letterSpacing:1,color:"var(--t3)"}}>
            <span>{t('pricing.feature')}</span><span style={{textAlign:"center"}}>{t('pricing.freeLabel')}</span><span style={{textAlign:"center",color:"var(--acc)"}}>Premium</span>
          </div>
          {featureRow("Casting submissions / day","3",t('pricing.unlimitedLabel'))}
          {featureRow("Headshots","1","Unlimited")}
          {featureRow("Photos & videos","—","Unlimited")}
          {featureRow("Browse castings","✓","✓")}
          {featureRow("Basic actor profile","✓","✓")}
          {featureRow("Premium profile features","—","✓")}
          {featureRow("Profile improvement suggestions","—","✓")}
          {featureRow("Actor Slate Video","—","✓")}
          {featureRow("Actor Business Card (with QR code)","—","✓")}
          {featureRow("Manager Mode","—","✓")}
          {featureRow("Price",t('pricing.freeLabel'),PREMIUM_PRICE)}
        </div>
      </div>

      <Footer onNavigate={onNavigate}/>
    </div>
  );
}

