// ─────────────────────────────────────────
// MediaViewer — unified full-screen lightbox for photos + videos
// items: [{type:"photo"|"video", url, title?}]
// startIdx: which item to open first
function MediaViewer({items,startIdx,onClose}){
  const [idx,setIdx]=useState(startIdx||0);
  const [animClass,setAnimClass]=useState("");
  const touchStartX=useRef(null);
  const animRef=useRef(null);

  const go=useCallback((dir)=>{
    const cls=dir>0?"mv-in-left":"mv-in-right";
    setAnimClass("");
    // allow repaint then apply class
    requestAnimationFrame(()=>{
      requestAnimationFrame(()=>{
        setIdx(x=>(x+dir+items.length)%items.length);
        setAnimClass(cls);
      });
    });
  },[items.length]);

  useEffect(()=>{
    const onKey=(e)=>{
      if(e.key==="Escape")onClose();
      if(e.key==="ArrowLeft")go(-1);
      if(e.key==="ArrowRight")go(1);
    };
    window.addEventListener("keydown",onKey);
    return()=>window.removeEventListener("keydown",onKey);
  },[go,onClose]);

  const item=items[Math.min(idx,items.length-1)];
  if(!item)return null;

  return(
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.95)",zIndex:9000,display:"flex",alignItems:"center",justifyContent:"center",userSelect:"none"}}
      onClick={onClose}
      onTouchStart={e=>{touchStartX.current=e.touches[0].clientX;}}
      onTouchEnd={e=>{
        if(touchStartX.current===null)return;
        const dx=e.changedTouches[0].clientX-touchStartX.current;
        touchStartX.current=null;
        if(Math.abs(dx)>50)go(dx<0?1:-1);
      }}>

      {/* Counter */}
      {items.length>1&&<div style={{position:"absolute",top:20,left:24,color:"rgba(255,255,255,0.5)",fontSize:12,fontWeight:700,letterSpacing:1,zIndex:2}}>{idx+1}&nbsp;/&nbsp;{items.length}</div>}

      {/* Close */}
      <button onClick={e=>{e.stopPropagation();onClose();}}
        style={{position:"absolute",top:14,right:18,background:"rgba(255,255,255,0.13)",border:"none",borderRadius:"50%",width:46,height:46,fontSize:24,color:"#fff",cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",zIndex:2,backdropFilter:"blur(4px)"}}>×</button>

      {/* Media — key on idx so video restarts; animClass drives slide.
          Both photo and video fill the full 90vw×86vh viewport box and use
          object-fit:contain so content is maximised without distortion.
          Portrait content gets pillar-boxed; landscape gets letter-boxed —
          the dark overlay behind acts as natural black bars. */}
      <div key={idx} className={animClass}
        style={{display:"flex",flexDirection:"column",alignItems:"center",gap:8,zIndex:1}}
        onClick={e=>e.stopPropagation()}>
        {item.type==="photo"
          ?<img src={item.url} alt={item.title||""} style={{width:"90vw",height:"86vh",objectFit:"contain",borderRadius:8,display:"block"}}/>
          :<video src={item.url} autoPlay controls playsInline style={{width:"90vw",height:"86vh",objectFit:"contain",borderRadius:8,background:"#000",outline:"none",display:"block"}}/>
        }
        {item.title&&<div style={{color:"rgba(255,255,255,0.75)",fontSize:12,fontWeight:600,background:"rgba(0,0,0,0.55)",padding:"3px 14px",borderRadius:6,maxWidth:"80vw",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{item.title}</div>}
      </div>

      {/* Left arrow */}
      {items.length>1&&<button onClick={e=>{e.stopPropagation();go(-1);}}
        style={{position:"absolute",left:10,top:"50%",transform:"translateY(-50%)",background:"rgba(255,255,255,0.13)",border:"none",borderRadius:"50%",width:54,height:54,fontSize:34,color:"#fff",cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",zIndex:2,backdropFilter:"blur(4px)",lineHeight:1}}>&#8249;</button>}

      {/* Right arrow */}
      {items.length>1&&<button onClick={e=>{e.stopPropagation();go(1);}}
        style={{position:"absolute",right:10,top:"50%",transform:"translateY(-50%)",background:"rgba(255,255,255,0.13)",border:"none",borderRadius:"50%",width:54,height:54,fontSize:34,color:"#fff",cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",zIndex:2,backdropFilter:"blur(4px)",lineHeight:1}}>&#8250;</button>}
    </div>
  );
}

// ─────────────────────────────────────────
// SmartVideo: adapts container to video orientation after metadata loads
// Portrait videos get a narrow centered card; landscape gets full-width 16:9.
function SmartVideo({src,title}){
  const [orient,setOrient]=useState(null); // null=unknown, "portrait", "landscape"
  const handleMeta=e=>{
    const v=e.target;
    setOrient(v.videoHeight>v.videoWidth?"portrait":"landscape");
  };
  const wrapStyle=orient==="portrait"
    ?{maxWidth:300,margin:"0 auto",background:"#000",borderRadius:8,overflow:"hidden"}
    :{width:"100%",background:"#000",borderRadius:8,overflow:"hidden"};
  const vidStyle=orient==="portrait"
    ?{width:"100%",height:"auto",display:"block"}
    :{width:"100%",aspectRatio:"16/9",objectFit:"contain",display:"block"};
  return(
    <div style={{borderRadius:8,overflow:"hidden",background:"#111"}}>
      <div style={wrapStyle}>
        <video src={src} controls preload="metadata" onLoadedMetadata={handleMeta} style={vidStyle}/>
      </div>
      {title&&<div style={{padding:"5px 10px",fontSize:11,color:"var(--t2)",fontWeight:600,background:"var(--s2)"}}>{title}</div>}
    </div>
  );
}

// ShowcaseVideoTile — fixed 3:4 portrait aspect ratio tile; clicking opens full-screen modal.
// Uses #t=0.1 so the browser seeks to the first real frame and shows a thumbnail.
// objectFit:"contain" lets portrait AND landscape videos display without cropping.
function ShowcaseVideoTile({v,onOpen}){
  return(
    <div style={{position:"relative",overflow:"hidden",background:"#111",cursor:"pointer",borderRadius:8,aspectRatio:"3/4"}}
      onClick={()=>onOpen&&onOpen(v)}>
      <video src={`${v.url}#t=0.1`} preload="metadata" playsInline muted
        style={{position:"absolute",inset:0,width:"100%",height:"100%",objectFit:"contain",display:"block",pointerEvents:"none"}}/>
      <div style={{position:"absolute",inset:0,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",background:"rgba(0,0,0,0.38)"}}>
        <div style={{width:44,height:44,borderRadius:"50%",background:"rgba(255,255,255,0.92)",display:"flex",alignItems:"center",justifyContent:"center",boxShadow:"0 2px 12px rgba(0,0,0,0.4)"}}>
          <div style={{width:0,height:0,borderTop:"10px solid transparent",borderBottom:"10px solid transparent",borderLeft:"18px solid #111",marginLeft:4}}/>
        </div>
        {v.title&&<div style={{marginTop:8,fontSize:11,color:"#fff",fontWeight:600,padding:"2px 10px",background:"rgba(0,0,0,0.55)",borderRadius:4,maxWidth:"85%",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{v.title}</div>}
      </div>
    </div>
  );
}

// ═══════════════════════════════════════════
// PAGE: TALENT PROFILE VIEW
// ═══════════════════════════════════════════
function TalentProfile({talent,onBack,onNavigate,session,myProfile}){
  const vpw=useViewportWidth();
  const isMobile=vpw<768;
  const viewerIsCd=!!myProfile&&(myProfile.user_type==="cd"||myProfile.user_type==="admin"||myProfile.user_type==="super_admin");
  const talentDbId=typeof talent.id==="string"&&/^[0-9a-f]{8}-/i.test(String(talent.id))?talent.id:null;
  const [cdAction,setCdAction]=useState(null);
  const [showReport,setShowReport]=useState(false);
  const [dbCredits,setDbCredits]=useState(null);
  const [uploadedVideos,setUploadedVideos]=useState([]);
  const [freshProfile,setFreshProfile]=useState(null);
  const [showAllMedia,setShowAllMedia]=useState(false);
  const [mediaViewer,setMediaViewer]=useState(null); // {items:[{type,url,title?}], idx}

  useEffect(()=>{
    if(!talentDbId){setDbCredits([]);return;}
    (async()=>{
      try{
        // Fetch full profile so all fields (photos, video_links, stats, etc.) are current —
        // prevents stale/deleted data from appearing in the CD view.
        const {data}=await window.sb.from("profiles")
          .select("*")
          .eq("id",talentDbId).maybeSingle();
        if(data)setFreshProfile(data);
      }catch(_){}
      try{
        const {data}=await window.sb.from("talent_credits")
          .select("*").eq("user_id",talentDbId)
          .order("credit_year",{ascending:false}).order("display_order");
        setDbCredits(data||[]);
      }catch(_){setDbCredits([]);}
      try{
        const {data}=await window.sb.from("profile_media")
          .select("*").eq("user_id",talentDbId).eq("media_type","video")
          .order("display_order").order("created_at");
        setUploadedVideos(data||[]);
      }catch(_){}
    })();
  },[talentDbId]);

  const parseLegacyCredits=(c)=>{
    if(!c)return [];
    if(Array.isArray(c))return c;
    return String(c).split("\n").map(l=>l.trim()).filter(Boolean).map(line=>{
      const parts=line.split("·").map(p=>p.trim());
      return {role:parts[0]||"",project:parts[1]||"",type:"",year:parts[2]||""};
    });
  };
  const legacyCredits=parseLegacyCredits(talent.credits);

  // Build gallery from fresh profile data when available so new/deleted photos reflect immediately.
  const freshHeadshot=freshProfile?.headshot_url||talent.img;
  // Filter headshot out of additional_photos to prevent duplication in gallery/showcase
  const freshAdditional=(Array.isArray(freshProfile?.additional_photos)?freshProfile.additional_photos:(talent.additional_photos||[])).filter(u=>u&&u!==freshHeadshot);
  const _galSeen=new Set();const gallery=[];
  [talent._selectedPhoto,freshHeadshot,...freshAdditional].forEach(u=>{if(u&&!_galSeen.has(u)){_galSeen.add(u);gallery.push(u);}});
  if(!gallery.length)gallery.push(talent.img||"");
  // Intentionally ignore video_links (old YouTube/Vimeo URL system). Videos are now
  // upload-only via profile_media. Using video_links would surface deleted external links.
  const rawSkills=freshProfile?.skills??talent.skills;
  const skills=Array.isArray(rawSkills)?rawSkills:(rawSkills?String(rawSkills).split(",").map(s=>s.trim()).filter(Boolean):[]);
  const rawSocialLinks=freshProfile?.social_links??talent.social_links;
  const socialLinks=(rawSocialLinks&&typeof rawSocialLinks==="object")?rawSocialLinks:{};

  const allSocialLinks=[];
  SOCIAL_LINK_FIELDS.forEach(({key,label})=>{
    const v=socialLinks[key];
    if(v&&v.trim())allSocialLinks.push({key,label,url:v.trim()});
  });
  if(!socialLinks.instagram_url&&talent.instagram)allSocialLinks.unshift({key:"instagram",label:"Instagram",url:talent.instagram.startsWith("http")?talent.instagram:`https://instagram.com/${talent.instagram.replace(/^@/,"")}`});

  const creditsByCategory={};
  if(dbCredits&&dbCredits.length){
    CREDIT_CATEGORIES.forEach(cat=>{
      const rows=dbCredits.filter(c=>c.category===cat);
      if(rows.length)creditsByCategory[cat]=rows;
    });
  }
  const hasStructuredCredits=Object.keys(creditsByCategory).length>0;

  // Build unified video list: only uploaded videos (profile_media table).
  // reel_url is a fallback only if it points to uploaded storage (not YouTube/Vimeo).
  const reelUrlRaw=freshProfile?.reel_url||talent.reel_url||"";
  const reelIsExternal=/(youtube\.com|youtu\.be|vimeo\.com)/i.test(reelUrlRaw);
  const allVideoItems=[
    ...uploadedVideos.map(v=>({kind:"upload",...v})),
    ...(!uploadedVideos.length&&reelUrlRaw&&!reelIsExternal?[{kind:"reel",url:reelUrlRaw,title:"Demo Reel"}]:[]),
  ];
  const hasVid=allVideoItems.length>0;
  // Build showcase tiles using saved showcase_order if available, else default ordering
  const savedShowcaseOrder=freshProfile?.showcase_order;
  let showcaseTiles=[];
  let extraMedia=[];
  if(savedShowcaseOrder&&savedShowcaseOrder.length>0){
    const _tvMap={};allVideoItems.forEach(v=>{if(v.id)_tvMap[v.id]=v;});
    const _tpSet=new Set(freshAdditional);
    const orderedAll=savedShowcaseOrder.map(item=>{
      if(item.type==="photo"&&_tpSet.has(item.id))return{_tile:"photo",url:item.id};
      if(item.type==="video"&&_tvMap[item.id])return{..._tvMap[item.id],_tile:"video"};
      return null;
    }).filter(Boolean);
    const orderedPhotoIds=new Set(savedShowcaseOrder.filter(i=>i.type==="photo").map(i=>i.id));
    const orderedVideoIds=new Set(savedShowcaseOrder.filter(i=>i.type==="video").map(i=>i.id));
    const unorderedVideos=allVideoItems.filter(v=>v.id&&!orderedVideoIds.has(v.id)).map(v=>({...v,_tile:"video"}));
    const unorderedPhotos=freshAdditional.filter(u=>!orderedPhotoIds.has(u)).map(u=>({_tile:"photo",url:u}));
    const allItems=[...orderedAll,...unorderedVideos,...unorderedPhotos];
    showcaseTiles=allItems.slice(0,4);
    extraMedia=allItems.slice(4);
  }else{
    const showcaseVideos=allVideoItems.slice(0,2);
    const showcasePhotos=freshAdditional.slice(0,2);
    showcaseTiles=[
      ...showcaseVideos.map(v=>({...v,_tile:"video"})),
      ...showcasePhotos.map(u=>({_tile:"photo",url:u})),
    ].slice(0,4);
    extraMedia=[
      ...allVideoItems.slice(2).map(v=>({...v,_tile:"video"})),
      ...freshAdditional.slice(showcasePhotos.length).map(u=>({_tile:"photo",url:u})),
    ];
  }
  const hasShowcase=showcaseTiles.length>0;
  const hasExtraMedia=extraMedia.length>0;

  // Unified ordered items list for the full-screen MediaViewer
  // Order: headshot → showcase tiles (L→R, top→bottom) → extra media
  const _allViewerItems=[
    {type:"photo",url:freshHeadshot||talent.img},
    ...showcaseTiles.map(t=>t._tile==="video"?{type:"video",url:t.url,title:t.title||null}:{type:"photo",url:t.url}),
    ...extraMedia.map(t=>t._tile==="video"?{type:"video",url:t.url,title:t.title||null}:{type:"photo",url:t.url}),
  ].filter(m=>m.url);
  const openMedia=(idx)=>setMediaViewer({items:_allViewerItems,idx:Math.max(0,idx)});

  const sectionHead=(title,extra)=>(
    <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:12}}>
      <div style={{fontSize:13,fontWeight:700,letterSpacing:"0.07em",textTransform:"uppercase",color:"var(--t3)"}}>{title}</div>
      {extra}
    </div>
  );

  const agentOrRep=freshProfile?.representation||freshProfile?.agent||talent.agent;
  const trainingText=freshProfile?.training||talent.training;
  const resumeUrl=freshProfile?.resume_url||talent.resume_url||null;
  const bioText=freshProfile?.bio||talent.bio;
  const locationText=freshProfile?.location||talent.location;
  const unionText=freshProfile?.union_status||talent.union||talent.union_status;

  const statsData=[
    ["Height",freshProfile?.height||talent.height],
    ["Weight",freshProfile?.weight||talent.weight],
    ["Hair",freshProfile?.hair||talent.hair],
    ["Eyes",freshProfile?.eyes||talent.eyes],
    ["Age",freshProfile?.age||talent.age],
    ["Gender",freshProfile?.gender||talent.gender],
    ["Ethnicity",freshProfile?.ethnicity||talent.ethnicity],
    ["Body",freshProfile?.body_type||talent.body_type],
    ["Plays",freshProfile?.age_range||talent.age_range],
  ].filter(([,v])=>v);

  const isOwnProfile=talent?.id&&talent.id===session?.user?.id;

  return(<div className="page">
    {isOwnProfile&&(
      <div style={{background:"#111",border:"1px solid #333",borderRadius:10,padding:"10px 16px",marginBottom:16,display:"flex",alignItems:"center",justifyContent:"space-between",flexWrap:"wrap",gap:10}}>
        <div style={{fontSize:13,color:"#fff",fontWeight:600}}>👁 Previewing your public profile — this is how casting directors see you.</div>
        <button style={{background:"#fff",color:"#111",border:"none",borderRadius:6,padding:"6px 14px",fontSize:12,fontWeight:700,cursor:"pointer"}} onClick={onBack}>← Back to Edit Profile</button>
      </div>
    )}
    <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",gap:10,marginBottom:16,flexWrap:"wrap"}}>
      {!isOwnProfile&&<button className="btn-s btn-sm" onClick={onBack}>← Back</button>}
      {!isOwnProfile&&talent?.id&&<button className="btn-s btn-sm" onClick={()=>setShowReport(true)} style={{color:"var(--t3)",fontSize:11}} title="Report this profile">⚑ Report</button>}
    </div>
    <ReportModal open={showReport} onClose={()=>setShowReport(false)} session={session} target={talent?.id?{kind:"profile",id:talent.id}:null}/>

    {talent._coverNote&&<div className="card" style={{padding:"12px 16px",marginBottom:14,borderLeft:"3px solid var(--acc)",background:"var(--s1)"}}>
      <div style={{fontSize:10,fontWeight:700,letterSpacing:"0.08em",textTransform:"uppercase",color:"var(--t3)",marginBottom:3}}>Cover note from {talent.name||"the applicant"}</div>
      <p style={{fontSize:13,lineHeight:1.6,fontStyle:"italic",color:"var(--t1)"}}>"{talent._coverNote}"</p>
      {talent._roleName&&<p style={{fontSize:11,color:"var(--t3)",marginTop:4}}>Submitted for: <strong>{talent._roleName}</strong></p>}
    </div>}

    {/* ── MEDIA SHOWCASE: Backstage-style 1 large headshot + 2×2 tile grid ── */}
    {mediaViewer&&<MediaViewer items={mediaViewer.items} startIdx={mediaViewer.idx} onClose={()=>setMediaViewer(null)}/>}
    <div style={{marginBottom:16}}>
      {/* Backstage-style showcase: equal 1fr/1fr columns so tiles are consistent portrait
          cards (3:4) that drive container height — headshot fills that same height. */}
      <div className="talent-profile-media-grid" style={{
        display:"grid",
        gridTemplateColumns:(!isMobile&&hasShowcase)?"1fr 1fr":"1fr",
        gap:"8px",
        background:"var(--bg)",
        borderRadius:12,
        overflow:"hidden"
      }}>
        {/* Left: large main headshot — idx 0 in unified viewer */}
        <div style={{position:"relative",background:"#111",overflow:"hidden",cursor:"zoom-in",borderRadius:8,minHeight:isMobile?240:0}} onClick={()=>openMedia(0)}>
          <img
            src={freshHeadshot||talent.img||"https://placehold.co/400x600/e5e5e5/999?text=No+Headshot"}
            alt={talent.name}
            style={{width:"100%",height:"100%",objectFit:"cover",objectPosition:"center top",display:"block",minHeight:isMobile?240:0}}
          />
          {talent._selectedPhoto&&talent._selectedPhoto!==freshHeadshot&&(
            <div style={{position:"absolute",bottom:0,left:0,right:0,padding:"6px 10px",background:"rgba(0,0,0,0.55)",fontSize:10,color:"#fff",textAlign:"center"}}>↑ Chosen for this submission</div>
          )}
        </div>

        {/* Right: 2×2 grid — showcase tiles at idx 1…showcaseTiles.length */}
        {hasShowcase&&(
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"8px",background:"var(--bg)",alignContent:"start"}}>
            {showcaseTiles.map((tile,i)=>(
              tile._tile==="video"
              ?<ShowcaseVideoTile key={tile.id||i} v={tile} onOpen={()=>openMedia(1+i)}/>
              :<div key={i} style={{position:"relative",overflow:"hidden",background:"#111",cursor:"zoom-in",borderRadius:8,aspectRatio:"3/4"}}
                onClick={()=>openMedia(1+i)}>
                <img src={tile.url} alt={`Photo ${i+1}`} style={{position:"absolute",inset:0,width:"100%",height:"100%",objectFit:"cover",objectPosition:"center",display:"block"}}/>
              </div>
            ))}
            {/* Empty slots invisible so they don't look like black boxes */}
            {Array.from({length:Math.max(0,4-showcaseTiles.length)}).map((_,i)=>(
              <div key={`empty-${i}`} style={{aspectRatio:"3/4",background:"var(--bg)"}}/>
            ))}
          </div>
        )}
      </div>

      {/* View More Media / View Less — extra tiles at idx 1+showcaseTiles.length… */}
      {hasExtraMedia&&(
        <div style={{marginTop:8}}>
          <button onClick={()=>setShowAllMedia(v=>!v)}
            style={{width:"100%",padding:"14px 18px",background:"#111",border:"none",borderRadius:8,fontSize:13,fontWeight:700,color:"#fff",cursor:"pointer",textAlign:"center",letterSpacing:"0.04em",display:"flex",alignItems:"center",justifyContent:"center",gap:8,boxShadow:"0 1px 4px rgba(0,0,0,0.18)"}}>
            {showAllMedia
              ?<>&#9650;&nbsp; View Less</>
              :<>&#9660;&nbsp; View More Media{extraMedia.length>0?` (${extraMedia.length})`:""}</>}
          </button>
          {showAllMedia&&(
            <div style={{marginTop:10,display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(220px,1fr))",gap:8}}>
              {extraMedia.map((item,i)=>(
                item._tile==="video"
                ?<div key={item.id||i} style={{position:"relative",background:"#111",borderRadius:8,overflow:"hidden",cursor:"pointer",border:"1px solid var(--bdr)",aspectRatio:"3/4"}}
                  onClick={()=>openMedia(1+showcaseTiles.length+i)}>
                  <video src={`${item.url}#t=0.1`} preload="metadata" muted playsInline
                    style={{position:"absolute",inset:0,width:"100%",height:"100%",objectFit:"contain",display:"block",pointerEvents:"none"}}/>
                  <div style={{position:"absolute",inset:0,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",background:"rgba(0,0,0,0.38)"}}>
                    <div style={{width:40,height:40,borderRadius:"50%",background:"rgba(255,255,255,0.92)",display:"flex",alignItems:"center",justifyContent:"center",boxShadow:"0 2px 12px rgba(0,0,0,0.4)"}}>
                      <div style={{width:0,height:0,borderTop:"9px solid transparent",borderBottom:"9px solid transparent",borderLeft:"16px solid #111",marginLeft:4}}/>
                    </div>
                    {item.title&&<div style={{marginTop:7,fontSize:11,color:"#fff",fontWeight:600,padding:"2px 10px",background:"rgba(0,0,0,0.6)",borderRadius:4,maxWidth:"85%",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{item.title}</div>}
                  </div>
                </div>
                :<div key={i} style={{cursor:"zoom-in",overflow:"hidden",borderRadius:8,background:"#111",position:"relative"}}
                  onClick={()=>openMedia(1+showcaseTiles.length+i)}>
                  <img src={item.url} alt={`Photo ${i+1}`}
                    style={{width:"100%",aspectRatio:"3/4",objectFit:"cover",objectPosition:"center",display:"block"}}
                    loading="lazy"/>
                </div>
              ))}
            </div>
          )}
        </div>
      )}

      {/* Profile info card */}
      <div className="card" style={{padding:"20px 22px",marginTop:10}}>
        {/* Tags row */}
        <div style={{display:"flex",gap:6,marginBottom:10,flexWrap:"wrap",alignItems:"center"}}>
          <span className="tag tag-acc" style={{fontSize:11}}>{unionText||"Non-Union"}</span>
          {talent.type&&<span className="tag" style={{fontSize:11}}>{talent.type}</span>}
        </div>

        {/* Name */}
        <h1 style={{fontSize:32,fontWeight:800,letterSpacing:"-1px",marginBottom:4,lineHeight:1.1}}>{freshProfile?.display_name||talent.name||talent.display_name||"—"}</h1>

        {/* Location & rep */}
        {locationText&&<p style={{color:"var(--t2)",fontSize:16,marginBottom:3}}>{locationText}</p>}
        {agentOrRep&&<p style={{color:"var(--t2)",fontSize:15,marginBottom:8}}>Rep: {agentOrRep}</p>}

        {/* Social icons — right in the header area */}
        {allSocialLinks.length>0&&(
          <div style={{display:"flex",gap:8,flexWrap:"wrap",alignItems:"center",marginBottom:14}}>
            {allSocialLinks.map(({key,label,url},i)=>{
              const href=url.startsWith("http")?url:`https://${url}`;
              return(
                <a key={i} href={href} target="_blank" rel="noopener noreferrer" title={label}
                  style={{width:44,height:44,borderRadius:10,background:"#fff",border:"1.5px solid #e0e0e0",display:"inline-flex",alignItems:"center",justifyContent:"center",color:"#000",textDecoration:"none",flexShrink:0,boxShadow:"0 1px 3px rgba(0,0,0,0.06)"}}>
                  <SocialIcon platform={key} size={22}/>
                </a>
              );
            })}
          </div>
        )}

        {/* Bio */}
        {bioText&&<p style={{color:"var(--t2)",fontSize:14,lineHeight:1.6,marginBottom:14}}>{bioText}</p>}

        {/* Appearance stats */}
        {statsData.length>0&&(
          <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fill,minmax(90px,1fr))",gap:"6px 16px",marginBottom:14,paddingTop:12,borderTop:"1px solid var(--bdr)"}}>
            {statsData.map(([l,v])=>(
              <div key={l}>
                <div style={{fontSize:10,color:"var(--t3)",textTransform:"uppercase",letterSpacing:"0.07em",marginBottom:1}}>{l}</div>
                <div style={{fontSize:14,fontWeight:600,color:"var(--t1)"}}>{v}</div>
              </div>
            ))}
          </div>
        )}

        {/* ── Card action bar — turns the public profile (where the actor's card
            QR/link lands) into an active submission tool. Adapts to the viewer.
            No anonymous writes: logged-out visitors are funneled to a free
            account, preserving the return path. ── */}
        {!isOwnProfile&&talentDbId&&talentDbId!==session?.user?.id&&(()=>{
          const talentFirst=(talent.name||talent.display_name||"this actor").split(" ")[0];
          return(
          <div style={{borderTop:"1px solid var(--bdr)",paddingTop:14,marginTop:2}}>
            {viewerIsCd?(
              <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
                <button className="btn-p btn-sm" onClick={()=>setCdAction("invite")}>📩 Invite to a Casting</button>
                <button className="btn-s btn-sm" onClick={()=>setCdAction("selftape")}>🎥 Request Self-Tape</button>
                <button className="btn-s btn-sm" onClick={()=>setCdAction("dm")}>💬 Message</button>
                <button className="btn-s btn-sm" onClick={()=>setCdAction("save")}>★ Save</button>
              </div>
            ):session?(
              <button className="btn-s btn-sm" onClick={()=>setCdAction("dm")}>💬 Message {talentFirst}</button>
            ):(
              <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",gap:12,flexWrap:"wrap"}}>
                <div style={{minWidth:0}}>
                  <div style={{fontWeight:700,fontSize:14,color:"var(--t1)"}}>Want to work with {talentFirst}?</div>
                  <div style={{fontSize:12.5,color:"var(--t2)",lineHeight:1.5,marginTop:2}}>Casting directors &amp; producers can invite {talentFirst} to a project or send a message — free to start.</div>
                </div>
                <button className="btn-p btn-sm" style={{flexShrink:0}} onClick={()=>{try{sessionStorage.setItem("sc_return_to",window.location.pathname+window.location.search);}catch(_){}onNavigate("register-cd");}}>Create a free account →</button>
              </div>
            )}
          </div>);
        })()}
      </div>
    </div>

    {/* ── SLATE VIDEO — private; shown to casting directors in submission review only, not on public profile ── */}

    {/* ── SKILLS ── */}
    {skills.length>0&&<div className="card" style={{padding:"16px 20px",marginBottom:12}}>
      {sectionHead("Skills")}
      <div style={{display:"flex",gap:6,flexWrap:"wrap"}}>
        {skills.map((s,i)=><span key={i} style={{padding:"5px 14px",background:"#EDE8DC",border:"1px solid #C9C3B2",borderRadius:20,fontSize:12.5,color:"#1A1A2E",fontWeight:600,letterSpacing:"0.02em",boxShadow:"0 1px 2px rgba(0,0,0,0.06)",display:"inline-block"}}>{s}</span>)}
      </div>
    </div>}

    {/* ── STRUCTURED CREDITS (from DB) ── */}
    {hasStructuredCredits&&<div className="card" style={{padding:"16px 20px",marginBottom:12}}>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:6,flexWrap:"wrap",gap:8}}>
        {sectionHead("Credits & Experience")}
        {resumeUrl&&<a href={resumeUrl} target="_blank" rel="noreferrer" className="btn-s btn-sm" style={{textDecoration:"none",fontSize:12}}>📄 Resume</a>}
      </div>
      <div className="credits-list">{CREDIT_CATEGORIES.filter(cat=>creditsByCategory[cat]).map(cat=>(
        <div key={cat} style={{marginBottom:20}}>
          <div style={{fontSize:12,fontWeight:700,letterSpacing:"0.07em",textTransform:"uppercase",color:"var(--acc)",marginBottom:8,paddingBottom:6,borderBottom:"1px solid var(--bdr)"}}>{cat}</div>
          {creditsByCategory[cat].map((c,i)=>(
            <div key={c.id||i} className="credit-row">
              <div className="credit-year">{c.credit_year||"—"}</div>
              <div className="credit-title">
                {c.production_title}
                {c.website_url&&<a href={c.website_url} target="_blank" rel="noopener noreferrer" style={{marginLeft:8,fontSize:12,color:"var(--blu)",textDecoration:"underline",fontWeight:500}}>↗ Link</a>}
              </div>
              <div className="credit-role">{c.role||""}</div>
              <div className="credit-meta">{[c.director_or_company,c.location].filter(Boolean).join(" · ")}</div>
            </div>
          ))}
        </div>
      ))}</div>
    </div>}

    {/* ── LEGACY CREDITS (plain-text / demo data) ── */}
    {!hasStructuredCredits&&(legacyCredits.length>0||resumeUrl)&&<div className="card" style={{padding:"16px 20px",marginBottom:12}}>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:6,flexWrap:"wrap",gap:8}}>
        {sectionHead("Credits & Experience")}
        {resumeUrl&&<a href={resumeUrl} target="_blank" rel="noreferrer" className="btn-s btn-sm" style={{textDecoration:"none",fontSize:12}}>📄 Resume</a>}
      </div>
      {legacyCredits.length>0
        ?<div className="credits-list">
            {legacyCredits.map((c,i)=>(
              <div key={i} className="credit-row">
                <div className="credit-year">{c.year||"—"}</div>
                <div className="credit-title">{c.project}</div>
                <div className="credit-role">{c.role||""}</div>
                <div className="credit-meta">{c.type}</div>
              </div>
            ))}
          </div>
        :<p style={{fontSize:13,color:"var(--t3)"}}>Resume attached — credits not added yet.</p>}
    </div>}

    {/* ── TRAINING ── */}
    {trainingText&&<div className="card" style={{padding:"16px 20px",marginBottom:12}}>
      {sectionHead("Training")}
      <p style={{fontSize:14,color:"var(--t1)",lineHeight:1.6}}>{trainingText}</p>
    </div>}

    {/* ── CAST ME AS ── */}
    {talentDbId&&<CastMeAsSection talentId={talentDbId}/>}

    {/* ── CD action modals ── */}
    {cdAction==="save"&&talentDbId&&<SaveToListModal cdId={session?.user?.id} talentId={talentDbId} talentName={talent.name||talent.display_name||"Talent"} onClose={()=>setCdAction(null)}/>}
    {cdAction==="invite"&&talentDbId&&<InviteToProjectModal cdId={session?.user?.id} talentId={talentDbId} talentName={talent.name||talent.display_name||"Talent"} onClose={()=>setCdAction(null)}/>}
    {cdAction==="dm"&&talentDbId&&<ComposeDMModal fromId={session?.user?.id} toId={talentDbId} toName={talent.name||talent.display_name||"Talent"} onClose={()=>setCdAction(null)}/>}
    {cdAction==="selftape"&&talentDbId&&<ComposeDMModal fromId={session?.user?.id} toId={talentDbId} toName={talent.name||talent.display_name||"Talent"} title={`Request a self-tape from ${(talent.name||talent.display_name||"this actor").split(" ")[0]}`} intro="Send a self-tape request. They'll get it in their inbox and can reply with a tape." initialBody={`Hi ${(talent.name||talent.display_name||"there").split(" ")[0]} — I'd love to see a self-tape from you for a project I'm casting. A short scene or monologue (60–90 seconds) is perfect. Thanks!`} onClose={()=>setCdAction(null)}/>}

    <Footer onNavigate={onNavigate}/></div>);
}

function generatePublicSlug(name){
  return(name||"").toLowerCase().replace(/[^a-z0-9\s]/g,"").trim().replace(/\s+/g,"-").replace(/-+/g,"-").slice(0,50)||"talent";
}

// ─── Public profile page rendered at /talent/:slug ───────────────────────────
function PublicTalentProfilePage({slug,onNavigate,session,myProfile}){
  const [talent,setTalent]=useState(null);
  const [loading,setLoading]=useState(true);
  const [notFound,setNotFound]=useState(false);
  useEffect(()=>{
    if(!slug){setNotFound(true);setLoading(false);return;}
    (async()=>{
      try{
        const {data}=await window.sb.from("profiles")
          .select("*").eq("public_slug",slug).eq("visible",true).maybeSingle();
        if(data){
          setTalent({
            id:data.id,name:data.display_name||"",display_name:data.display_name||"",
            img:data.headshot_url||"",type:"Talent",
            additional_photos:data.additional_photos||[],
            skills:data.skills||[],social_links:data.social_links||{},
            instagram:data.instagram||"",credits:data.credits||"",
            bio:data.bio,location:data.location,union_status:data.union_status,
            height:data.height,weight:data.weight,hair:data.hair,eyes:data.eyes,
            age:data.age,gender:data.gender,ethnicity:data.ethnicity,
            training:data.training,resume_url:data.resume_url,
            agent:data.agent||data.representation,reel_url:data.reel_url,
          });
        }else{setNotFound(true);}
      }catch(_){setNotFound(true);}
      setLoading(false);
    })();
  },[slug]);
  if(loading)return <PageLoader/>;
  if(notFound||!talent)return(
    <div style={{minHeight:"60vh",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:12,padding:24}}>
      <div style={{fontSize:48}}>🎭</div>
      <h2 style={{fontSize:20,fontWeight:700}}>Profile Not Found</h2>
      <p style={{color:"var(--t3)",fontSize:14,textAlign:"center"}}>This profile link may be invalid or the profile is no longer available.</p>
      <button className="btn-p btn-sm" onClick={()=>onNavigate("home")}>Back to Home</button>
    </div>
  );
  return <TalentProfile talent={talent} onBack={()=>window.history.back()} onNavigate={onNavigate} session={session} myProfile={myProfile}/>;
}

// ─── Copy-link + view buttons shown on MyProfilePage ─────────────────────────
function PublicProfileButtons({slug}){
  const [copied,setCopied]=useState(false);
  if(!slug)return(<button style={{background:"var(--s2)",color:"var(--t3)",border:"1px solid var(--bdr)",borderRadius:7,padding:"8px 14px",fontSize:12,fontWeight:600,cursor:"default"}} disabled>Setting up profile URL…</button>);
  const url=`${window.location.origin}/talent/${encodeURIComponent(slug)}`;
  const copy=()=>{
    try{navigator.clipboard.writeText(url).then(()=>{setCopied(true);setTimeout(()=>setCopied(false),2500);}).catch(()=>{fallbackCopy();});}
    catch(_){fallbackCopy();}
    function fallbackCopy(){try{const t=document.createElement("textarea");t.value=url;document.body.appendChild(t);t.select();document.execCommand("copy");document.body.removeChild(t);setCopied(true);setTimeout(()=>setCopied(false),2500);}catch(_){}}
  };
  return(<>
    <button style={{background:"var(--s2)",color:"var(--t2)",border:"1px solid var(--bdr)",borderRadius:7,padding:"8px 14px",fontSize:12,fontWeight:600,cursor:"pointer",transition:"color .15s"}} onClick={copy}>
      {copied?"✓ Link copied!":"📋 Copy Profile Link"}
    </button>
    <button style={{background:"#111",color:"#fff",border:"1px solid #333",borderRadius:7,padding:"8px 18px",fontSize:13,fontWeight:700,cursor:"pointer",letterSpacing:"0.02em"}} onClick={()=>window.open(`/talent/${encodeURIComponent(slug)}`,"_blank")}>👁 View Public Profile →</button>
  </>);
}

